import "thirst::time" as t;
glass main() -> Int {
  drink n: Int = t.now();
  pour(n > 0);
  return 0;
}

import "thirst::crypto" as crypto;
glass main() -> Int {
  drink h: String = crypto.sha256("x");
  pour(length(h) == 64);
  return 0;
}

import "thirst::reservoir" as res;
glass main() -> Int {
  drink xs: Reservoir[Int] = [1, 2, 3];
  pour(res.size(xs));
  return 0;
}

import "thirst::crypto" as cry;
glass main() -> Int {
  drink h: String = cry.sha256("test");
  pour(length(h) > 0);
  return 0;
}

module myapp
mode core

glass main() -> Int {
  pour("running");
  return 0;
}

module bare

glass main() -> Int {
  pour("bare");
  return 0;
}

import "thirst::fs" as fs;
glass main() -> Int {
  pour(fs.exists("."));
  return 0;
}

import "thirst::json" as json;
glass main() -> Int {
  drink s: String = json.stringify("hello");
  pour(s);
  return 0;
}

import "thirst::env" as env;
glass main() -> Int {
  drink path: Any = env.get("PATH");
  pour(path != empty);
  return 0;
}

import "thirst::collections" as col;
glass main() -> Int {
  drink xs: Reservoir[Int] = [3, 1, 2];
  drink sorted: Any = col.sort(xs);
  pour(get(sorted, 0));
  return 0;
}

module governed_app
mode governed

glass main() -> Int {
  pour("governed");
  return 0;
}

import "thirst::nonexistent" as bad;
glass main() -> Int {
  return 0;
}

import "thirst::path" as p;
glass main() -> Int {
  drink path: String = p.join("foo", "bar");
  pour(contains(path, "bar"));
  return 0;
}

import "thirst::path" as p;
glass main() -> Int {
  drink d: String = p.dirname("/foo/bar/baz.txt");
  pour(contains(d, "bar"));
  return 0;
}

import "thirst::process" as proc;
glass main() -> Int {
  drink p: Any = proc.pid();
  pour(p > 0);
  return 0;
}
